const html = $json.data || '';
const cpf_id = $json.cpf_id || $json.id;

// =============================================
// 1. PEGAR EXCLUSIVAMENTE O BLOCO "Historico de Telefone"
// =============================================
function pegarBlocoHistorico() {
  const normalizar = (str) => str.normalize("NFD").replace(/[\u0300-\u036f]/g, "").replace(/[^\w]/g, "").toLowerCase();
  const tituloBusca = normalizar("Historico de Telefone");
  const regexH2 = /<h2[^>]*>([\s\S]*?)<\/h2>/gi;
  let match;
  while ((match = regexH2.exec(html)) !== null) {
    if (normalizar(match[1]).includes(tituloBusca)) {
      const inicio = match.index + match[0].length;
      const resto = html.substring(inicio);
      const fim = resto.search(/<div class="bg-gray-800|$/);
      return html.substring(match.index, inicio + (fim >= 0 ? fim : resto.length));
    }
  }
  return null;
}

const blocoTelefone = pegarBlocoHistorico();

// Se não encontrou a sessão → retorna null
if (!blocoTelefone || blocoTelefone.includes("NÃO ENCONTRAMOS RESULTADOS")) {
  return [];
}

// =============================================
// 2. FUNÇÃO: Extrai valores APENAS dentro do bloco correto
// =============================================
function extrairDoBloco(chave) {
  const regex = new RegExp(`<strong>${chave}:?\\s*</strong>\\s*<span[^>]*>([^<]+)</span>`, 'gi');
  const valores = [];
  let match;
  while ((match = regex.exec(blocoTelefone)) !== null) {
    const valor = match[1].trim();
    if (valor !== "SEM RESULTADO" && valor !== "NÃO ENCONTRAMOS RESULTADOS") {
      valores.push(valor);
    }
  }
  return valores;
}

// =============================================
// 3. EXTRAIR TODOS OS CAMPOS
// =============================================
const ddds = extrairDoBloco("DDD");
const telefones = extrairDoBloco("TELEFONE");
const tiposCodigo = extrairDoBloco("TIPO DE TELEFONE");
const datasInclusao = extrairDoBloco("DATA DE INCLUSÃO");
const datasInformacao = extrairDoBloco("DATA DE INFORMAÇÃO");
const sigilos = extrairDoBloco("SIGILO");
const nsus = extrairDoBloco("NSU");
const classificacoes = extrairDoBloco("CLASSIFICAÇÃO");

// =============================================
// 4. SE NÃO TEM TELEFONE → RETORNA VAZIO
// =============================================
if (telefones.length === 0) {
  return [];
}

// =============================================
// 5. MAPEAMENTO DO TIPO
// =============================================
const mapaTipo = {
  "1": "Residencial",
  "2": "Comercial",
  "3": "Celular",
  "4": "WhatsApp"
};

// =============================================
// 6. MONTAR ARRAY DE TELEFONES
// =============================================
const total = Math.max(ddds.length, telefones.length, tiposCodigo.length);
const telefonesArray = Array.from({ length: total }, (_, i) => {
  const ddd = (ddds[i] || "").padStart(2, '0');
  const tel = telefones[i] || "";

  return {
    cpf_id: cpf_id,
    ddd: ddd,
    telefone: tel,
    telefone_completo: `${ddd}${tel}`.replace(/\D/g, ''),
    tipo_codigo: tiposCodigo[i] || "",
    tipo_texto: mapaTipo[tiposCodigo[i]] || "Outro",
    data_inclusao: datasInclusao[i] || null,
    data_informacao: datasInformacao[i] || null,
    sigilo: sigilos[i] === "1" ? 1 : 0,
    nsu: nsus[i] || null,
    classificacao: classificacoes[i] || null
  };
});

// =============================================
// 7. RETORNA UM ITEM POR TELEFONE
// =============================================
return telefonesArray.map(t => ({ json: t }));

const html = $json.data || '';
const cpf_id = $json.cpf_id || $json.id;

// =============================================
// 1. PEGAR BLOCO "Emails"
// =============================================
// Capturamos o conteúdo entre o título "Emails" e o próximo bloco ou fim da string
const blocoMatch = html.match(/<h2[^>]*>[\s\S]*?Emails[\s\S]*?<\/h2>([\s\S]*?)(?=<div class="bg-gray-800|$)/i);
if (!blocoMatch) return [];

const conteudoEmails = blocoMatch[1];

// =============================================
// 2. DIVIDIR EM REGISTROS INDIVIDUAIS
// =============================================
// Cada registro de e-mail começa com o rótulo "EMAIL:"
const partes = conteudoEmails.split(/<strong>EMAIL:?\s*<\/strong>/i);
// A primeira parte (índice 0) é o que vem antes do primeiro "EMAIL:", então removemos
partes.shift();

const resultados = [];

partes.forEach(parte => {
    let email = null;

    // TENTATIVA 1: EMAIL VISÍVEL
    const textoEmailMatch = parte.match(/<span[^>]*>([^<]+)<\/span>/i);
    if (textoEmailMatch && textoEmailMatch[1]) {
        const texto = textoEmailMatch[1].trim();
        if (texto && texto.includes('@') && !texto.includes('[email')) {
            email = texto.toLowerCase();
        }
    }

    // TENTATIVA 2: EMAIL OFUSCADO (Cloudflare)
    if (!email) {
        const cfMatch = parte.match(/data-cfemail=["']([a-f0-9]+)["'][^>]*>\[email&#160;protected\]/i);
        if (cfMatch && cfMatch[1]) {
            const cfemail = cfMatch[1];
            let decoded = '';
            const key = parseInt(cfemail.substr(0, 2), 16);
            for (let i = 2; i < cfemail.length; i += 2) {
                decoded += String.fromCharCode(parseInt(cfemail.substr(i, 2), 16) ^ key);
            }
            if (decoded.includes('@')) {
                email = decoded.toLowerCase();
            }
        }
    }

    // Se encontramos um e-mail válido, extraímos os outros campos desta "parte"
    if (email) {
        function extrair(chave) {
            const regex = new RegExp(`<strong>${chave}:?\\s*</strong>\\s*<span[^>]*>([^<]+)</span>`, 'i');
            const match = regex.exec(parte);
            return match && match[1] ? match[1].trim() : null;
        }

        const prioridade = extrair("PRIORIDADE");
        const score = extrair("SCORE DO EMAIL");
        const pessoal = extrair("EMAIL PESSOAL");
        const duplicado = extrair("EMAIL DUPLICADO");
        const blacklist = extrair("BLACKLIST");
        const estrutura = extrair("ESTRUTURA");
        const statusVt = extrair("STATUS DO VT");
        const dominio = extrair("DOMINIO");
        const mapas = extrair("MAPAS");
        const peso = extrair("PESO");
        const dataInclusao = extrair("DATA DE INCLUSÃO");

        resultados.push({
            json: {
                cpf_id,
                email,
                prioridade: prioridade ? parseInt(prioridade) : null,
                score_email: score || null,
                email_pessoal: pessoal === "S" ? 1 : 0,
                email_duplicado: duplicado === "N" ? 0 : 1,
                blacklist: blacklist === "N" ? 0 : 1,
                estrutura_valida: estrutura === "VALIDA" ? 1 : 0,
                status_vt: statusVt === "SEM EVIDENCIA" ? null : statusVt,
                dominio_publico: dominio === "PUBLICO" ? 1 : 0,
                mapas: mapas ? parseInt(mapas) : null,
                peso: peso ? parseInt(peso) : null,
                data_inclusao: dataInclusao || null
            }
        });
    }
});

return resultados;

const html = $json.data || '';
const cpf_id = $json.cpf_id || $json.id;

// =============================================
// 1. ISOLAR BLOCO "Covid"
// =============================================
const blocoCovidMatch = html.match(
  /<h2[^>]*>\s*Covid\s*<\/h2>([\s\S]*?)(?=<div class="bg-gray-800|$)/i
);

if (!blocoCovidMatch) return [];

const blocoCovid = blocoCovidMatch[1];

// =============================================
// 2. QUEBRAR EM REGISTROS (cada COR = 1 vacina)
// =============================================
const partes = blocoCovid.split(/<strong>COR:\s*<\/strong>/i);
partes.shift(); // remove lixo inicial

function extrair(parte, chave) {
  const regex = new RegExp(
    `<strong>${chave}:\\s*</strong>\\s*<span[^>]*>([^<]*)<\\/span>`,
    'i'
  );
  const match = regex.exec(parte);
  if (!match) return null;
  const valor = match[1].trim();
  if (valor === 'SEM INFORMACAO' || valor === 'SEM RESULTADO') return null;
  return valor;
}

const resultados = [];

partes.forEach(parte => {
  const nomeVacina = extrair(parte, 'NOME DA VACINA');
  const dataAplicacao = extrair(parte, 'DATA DE APLICAÇÃO');

  // Só segue se for vacina válida
  if (!nomeVacina || !dataAplicacao) return;

  // Converte data BR -> MySQL
  let dataMysql = null;
  if (dataAplicacao.match(/^\d{2}\/\d{2}\/\d{4}$/)) {
    const [d, m, y] = dataAplicacao.split('/');
    dataMysql = `${y}-${m}-${d} 00:00:00`;
  }

  resultados.push({
    json: {
      cpf_id,
      cor: extrair(parte, 'COR'),
      cns: extrair(parte, 'CNS'),
      mae: extrair(parte, 'NOME MAE'),
      nome_vacina: nomeVacina,
      descricao_vacina: extrair(parte, 'DESCRIÇÃO DA VACINA'),
      lote_vacina: extrair(parte, 'LOTE DA VACINA'),
      grupo_atendimento: extrair(parte, 'GRUPO DE ATENDIMENTO'),
      data_aplicacao: dataMysql,
      status: extrair(parte, 'STATUS'),
      nome_estabelecimento: extrair(parte, 'NOME DO ESTABELECIMENTO'),
      aplicador_vacina: extrair(parte, 'APLICADOR DE VACINA'),
      uf: extrair(parte, 'UF'),
      municipio: extrair(parte, 'MUNICIPIO'),
      bairro: extrair(parte, 'BAIRRO'),
      cep: extrair(parte, 'CEP')
    }
  });
});

return resultados;

const html = $json.data || '';
const cpf_id = $json.cpf_id || $json.id;

// ================================
// 1. EXTRAI BLOCO "Auxilio Emergencial"
// ================================
const blocoMatch = html.match(
  /<h2[^>]*>\s*Auxilio Emergencial\s*<\/h2>([\s\S]*?)(?=<div class="bg-gray-800|$)/i
);
if (!blocoMatch) return [];

const bloco = blocoMatch[1];

// ================================
// 2. QUEBRA EM LINHAS <p>
// ================================
const linhas = bloco.match(/<p class="text-gray-300">[\s\S]*?<\/p>/gi) || [];

const resultados = [];
let atual = {};

function extrair(label, texto) {
  const r = new RegExp(`<strong>${label}:?\\s*</strong>\\s*<span[^>]*>([^<]+)<\\/span>`, 'i');
  const m = r.exec(texto);
  return m ? m[1].trim() : null;
}

linhas.forEach(linha => {
  const mes = extrair('MES DE DISPONIBILIZAÇÃO', linha);
  if (mes) {
    if (Object.keys(atual).length > 0) {
      resultados.push({ ...atual });
      atual = {};
    }
    atual.cpf_id = cpf_id;
    atual.mes_disponibilizacao = mes;
  }

  const uf = extrair('UF', linha);
  if (uf) atual.uf = uf;

  const enquadramento = extrair('ENQUADRAMENTO', linha);
  if (enquadramento) atual.enquadramento = enquadramento;

  const parcela = extrair('PARCELA', linha);
  if (parcela) atual.parcela = parcela;

  const observacao = extrair('OBSERVAÇÃO', linha);
  if (observacao) atual.observacao = observacao;

  const valor = extrair('VALOR DO BENEFICIO', linha);
  if (valor) {
    atual.valor_beneficio = parseFloat(
      valor.replace('.', '').replace(',', '.')
    );
  }
});

// Último registro
if (Object.keys(atual).length > 0) {
  resultados.push(atual);
}

// Retorna apenas registros válidos
return resultados
  .filter(r => r.parcela && r.mes_disponibilizacao)
  .map(r => ({ json: r }));

const html = $json.data || '';
const cpf_id = $json.cpf_id || $json.id;

/**
 * 1️⃣ Isola somente o bloco "Rais - Histórico de Emprego"
 */
function pegarBlocoRais() {
  const normalizar = (str) =>
    str
      .normalize("NFD")
      .replace(/[\u0300-\u036f]/g, "")
      .replace(/[^\w]/g, "")
      .toLowerCase();

  const tituloBusca = normalizar("Rais - Histórico de Emprego");

  const regexH2 = /<h2[^>]*>([\s\S]*?)<\/h2>/gi;
  let match;

  while ((match = regexH2.exec(html)) !== null) {
    if (normalizar(match[1]).includes(tituloBusca)) {
      const inicio = match.index + match[0].length;
      const resto = html.substring(inicio);
      const fim = resto.search(/<div class=["']bg-gray-800|$/i);

      return html.substring(
        match.index,
        inicio + (fim >= 0 ? fim : resto.length)
      );
    }
  }
  return null;
}

const blocoRais = pegarBlocoRais();

/**
 * 2️⃣ IF SIMPLES: sem bloco, sem cpf → morre
 */
if (!cpf_id || !blocoRais || blocoRais.toUpperCase().includes("NÃO ENCONTRAMOS")) {
  return [];
}

/**
 * 3️⃣ Regex que captura UM REGISTRO COMPLETO DE RAIS
 */
const regexRais = /<strong>CNPJ:\s*<\/strong>\s*<span[^>]*>([^<]+)<\/span>[\s\S]*?<strong>RAZAO SOCIAL:\s*<\/strong>\s*<span[^>]*>([^<]+)<\/span>[\s\S]*?<strong>SITUAÇÃO:\s*<\/strong>\s*<span[^>]*>([^<]+)<\/span>[\s\S]*?<strong>DATA DE ENTREGA:\s*<\/strong>\s*<span[^>]*>([^<]+)<\/span>[\s\S]*?<strong>DATA DE ADMISSÃO:\s*<\/strong>\s*<span[^>]*>([^<]+)<\/span>[\s\S]*?<strong>DATA DE DESLIGAMENTO:\s*<\/strong>\s*<span[^>]*>([^<]+)<\/span>[\s\S]*?<strong>DATA DE CADASTRO:\s*<\/strong>\s*<span[^>]*>([^<]+)<\/span>[\s\S]*?<strong>FAIXA RENDA:\s*<\/strong>\s*<span[^>]*>([^<]+)<\/span>/gi;

const registros = [];
let match;

/**
 * 4️⃣ Loop igualzinho o da Claro
 */
while ((match = regexRais.exec(blocoRais)) !== null) {
  const cnpj = match[1].trim();

  // 👉 IF SIMPLES QUE VOCÊ PEDIU
  if (!cnpj) continue;

  registros.push({
    cpf_id,
    cnpj,
    razao_social: match[2].trim(),
    situacao: match[3].trim(),
    data_entrega: match[4].trim(),
    data_admissao: match[5].trim(),
    data_desligamento: match[6].trim(),
    data_cadastro: match[7].trim(),
    faixa_renda: match[8].trim(),
  });
}

/**
 * 5️⃣ Se não achou nada, não retorna lixo
 */
if (registros.length === 0) {
  return [];
}

/**
 * 6️⃣ Retorno padrão n8n
 */
return registros.map(r => ({ json: r }));

const html = $json.data || '';
const cpf_id = $json.cpf_id || $json.id;

function pegarBlocoINSS() {
  const normalizar = (str) =>
    str.normalize("NFD")
       .replace(/[\u0300-\u036f]/g, "")
       .replace(/[^\w]/g, "")
       .toLowerCase();

  const tituloBusca = normalizar("Inss");

  const regexH2 = /<h2[^>]*>([\s\S]*?)<\/h2>/gi;
  let match;

  while ((match = regexH2.exec(html)) !== null) {
    if (normalizar(match[1]).includes(tituloBusca)) {
      const inicio = match.index + match[0].length;
      const resto = html.substring(inicio);
      const fim = resto.search(/<div class=["']bg-gray-800|$/i);
      return html.substring(match.index, inicio + (fim >= 0 ? fim : resto.length));
    }
  }
  return null;
}

const bloco = pegarBlocoINSS();

if (!cpf_id || !bloco) {
  return [];
}

const regexItem = /<strong>NB:\s*<\/strong>\s*<span[^>]*>([^<]+)<\/span>[\s\S]*?<strong>ENTIDADE:\s*<\/strong>\s*<span[^>]*>([^<]+)<\/span>[\s\S]*?<strong>ESPECIE:\s*<\/strong>\s*<span[^>]*>([^<]+)<\/span>[\s\S]*?<strong>VALOR:\s*<\/strong>\s*<span[^>]*>([^<]+)<\/span>/gi;

const registros = [];
let m;

while ((m = regexItem.exec(bloco)) !== null) {
  const especieDescricao = m[3].trim();
  const especieCodigo = especieDescricao.split(' ')[0];

  registros.push({
    cpf_id,
    nb: m[1].trim(),
    entidade: m[2].trim(),
    especie: especieCodigo,
    especie_descricao: especieDescricao,
    valor: m[4].trim()
  });
}

return registros.map(r => ({ json: r }));

const html = $json.data || "";

// =============================================
// FUNÇÃO: Normalizar texto
// =============================================
function normalizar(str) {
  return str
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .replace(/[^\w]/g, "")
    .toLowerCase();
}

// =============================================
// FUNÇÃO: Pegar bloco por título (h2 ou h3)
// =============================================
function pegarBloco(tituloBusca) {
  const tituloNormalizado = normalizar(tituloBusca);
  // Aceita <h2> ou <h3>
  const regex = /<(h2|h3)[^>]*>([\s\S]*?)<\/\1>/gi;
  let match;
  while ((match = regex.exec(html)) !== null) {
    const tituloEncontrado = match[2] || "";
    if (normalizar(tituloEncontrado).includes(tituloNormalizado)) {
      const inicio = match.index + match[0].length;
      const resto = html.substring(inicio);
      // Para próximo heading ou div bg-gray-800 ou fim do conteúdo
      const fim = resto.search(/<(h[2-6])[^>]*>|div class="bg-gray-800|$/i);
      const fimPos = fim >= 0 ? fim : resto.length;
      return html.substring(match.index, inicio + fimPos);
    }
  }
  return null;
}

// =============================================
// FUNÇÃO: Extrair campo (flexível para o formato real)
// =============================================
function extrairCampo(bloco, chave) {
  if (!bloco) return null;
  // Padrão principal: <strong>CHAVE: </strong><span>VALOR</span>
  // Aceita variação de espaços, sem span obrigatório, etc.
  const regex = new RegExp(
    `<strong>\\s*${chave}\\s*[:.]?\\s*</strong>\\s*(?:<span[^>]*>)?\\s*([^<]+?)(?:</span>)?\\s*(?=<|$)`,
    "i"
  );
  const match = bloco.match(regex);
  if (!match) return null;
  let valor = match[1].trim();
  if (valor === "SEM RESULTADO" || valor === "NÃO ENCONTRAMOS RESULTADOS" || valor === "-") {
    return null;
  }
  return valor;
}

// =============================================
// FUNÇÃO: Extrair SCORE do TOPO (CSB8 e CSBA via blocos)
// =============================================
function extrairScoreTopo(html) {
  const dados = {
    csb8: null,
    csb8_faixa: null,
    csba: null,
    csba_faixa: null
  };

  // Bloco CSB8
  const blocoCsb8 = pegarBloco("CSB8 [SCORE]") || pegarBloco("CSB8");
  if (blocoCsb8) {
    const pontuacaoStr = extrairCampo(blocoCsb8, "PONTUAÇÃO");
    if (pontuacaoStr) {
      // Remove qualquer caractere não numérico e converte
      dados.csb8 = parseInt(pontuacaoStr.replace(/\D/g, ""), 10);
    }
    dados.csb8_faixa = extrairCampo(blocoCsb8, "FAIXA");
  }

  // Bloco CSBA (geralmente logo abaixo)
  const blocoCsba = pegarBloco("CSBA [SCORE]") || pegarBloco("CSBA");
  if (blocoCsba) {
    const pontuacaoStr = extrairCampo(blocoCsba, "PONTUAÇÃO");
    if (pontuacaoStr) {
      dados.csba = parseInt(pontuacaoStr.replace(/\D/g, ""), 10);
    }
    dados.csba_faixa = extrairCampo(blocoCsba, "FAIXA");
  }

  return dados;
}

// =============================================
// FUNÇÃO: Extrair imagens (Base64 ou URL)
// =============================================
function extrairImagens(html) {
  const imagens = [];
  const regex = /<img[^>]+src=["']([^"']+)["']/gi;
  let match;
  while ((match = regex.exec(html)) !== null) {
    const src = match[1];
    if (src.startsWith("data:image") || src.startsWith("http")) {
      imagens.push(src);
    }
  }
  return imagens;
}

// =============================================
// OBJETO FINAL
// =============================================
const resultado = {
  cpf: null,
  nome: null,
  data_nascimento: null,
  sexo: null,
  mae: null,
  pai: null,
  estado_civil: null,
  rg: null,
  orgao_emissor: null,
  uf_emissor: null,
  cbo: null,
  titulo_eleitor: null,
  zona: null,
  secao: null,
  renda: null,
  pis: null,
  csb8: null,
  csb8_faixa: null,
  csba: null,
  csba_faixa: null,
  poder_aquisitivo: null,
  fx_poder_aquisitivo: null,
  data_obito: null,
  fotos: []
};

// =============================================
// FOTOS
// =============================================
resultado.fotos = extrairImagens(html);

// =============================================
// SCORE (prioridade: blocos CSB8/CSBA)
// =============================================
const scoreTopo = extrairScoreTopo(html);
resultado.csb8 = scoreTopo.csb8;
resultado.csb8_faixa = scoreTopo.csb8_faixa;
resultado.csba = scoreTopo.csba;
resultado.csba_faixa = scoreTopo.csba_faixa;

// =============================================
// DADOS BÁSICOS
// =============================================
const blocoBasicos =
  pegarBloco("Dados Básicos") ||
  pegarBloco("DadosBasicos") ||
  pegarBloco("DadosBásicos");

if (!blocoBasicos) {
  return [
    {
      json: {
        erro: "Sessão 'Dados Básicos' não encontrada",
        preview: html.substring(0, 500)
      }
    }
  ];
}

resultado.nome = extrairCampo(blocoBasicos, "NOME");
resultado.cpf = extrairCampo(blocoBasicos, "CPF");
resultado.sexo = extrairCampo(blocoBasicos, "SEXO");
resultado.data_nascimento = extrairCampo(blocoBasicos, "NASCIMENTO");
resultado.mae = extrairCampo(blocoBasicos, "NOME DA MÃE");
resultado.pai = extrairCampo(blocoBasicos, "NOME DO PAI");
resultado.estado_civil = extrairCampo(blocoBasicos, "ESTADO CIVIL");
resultado.rg = extrairCampo(blocoBasicos, "RG");
resultado.orgao_emissor = extrairCampo(blocoBasicos, "ORGÃO EMISSOR");
resultado.uf_emissor = extrairCampo(blocoBasicos, "UF EMISSOR");
resultado.cbo = extrairCampo(blocoBasicos, "CBO");
resultado.renda = extrairCampo(blocoBasicos, "RENDA");
resultado.data_obito = extrairCampo(blocoBasicos, "DATA OBITO");

const tituloBasico = extrairCampo(blocoBasicos, "TITULO DE ELEITOR");

// =============================================
