const html = $json.data;
const cpf_id = $json.cpf_id;
const cpf = $json.cpf;

async function extrairFotos() {
  const photos = [];
  const defaultImage = 'https://st5.depositphotos.com/17433220/73304/i/450/depositphotos_733041150-stock-photo-silhouette-adult-man-male-avatar.jpg';

  console.log("=== INÍCIO EXTRAÇÃO ===");

  // ✅ 1) Cortar o HTML ATÉ a div alvo
  const stopDiv = '<div class="flex flex-wrap justify-center gap-4 mt-8">';
  const index = html.indexOf(stopDiv);

  if (index === -1) {
    console.log("❌ Div alvo não encontrada!");
    return [];
  }

  const htmlAteFotos = html.substring(0, index);

  console.log(`📌 HTML da área de fotos capturado: ${htmlAteFotos.length} chars`);

  // ✅ 2) Regex para pegar apenas imagens dentro desse trecho
  const regexImg = /<img[^>]+src=["']?([^"'\s>]+)["']?/gi;
  const matches = [...htmlAteFotos.matchAll(regexImg)];

  console.log(`📸 Imagens encontradas antes da div alvo: ${matches.length}`);

  // ✅ 3) Processar somente essas imagens
  for (const match of matches) {
    let src = match[1];
    if (!src || src.trim() === '') continue;

    // Ignora placeholder
    if (src === defaultImage) continue;

    try {
      // Base64 direto → só adicionar
      if (src.startsWith('data:image')) {
        photos.push({
          cpf_id,
          cpf,
          image_data: src,
          type: photos.length === 0 ? 'foto' : `foto${photos.length + 1}`
        });
        continue;
      }

      // Senão, baixar imagem via URL
      const response = await fetch(src);
      if (!response.ok) throw new Error(`Erro ao baixar imagem: ${response.status}`);

      const buffer = Buffer.from(await response.arrayBuffer());
      const contentType = response.headers.get('content-type') || 'image/jpeg';
      const base64Image = `data:${contentType};base64,${buffer.toString('base64')}`;

      photos.push({
        cpf_id,
        cpf,
        image_data: base64Image,
        type: photos.length === 0 ? 'foto' : `foto${photos.length + 1}`
      });

    } catch (err) {
      console.log(`❌ Erro com imagem ${src}: ${err.message}`);
    }
  }

  // ✅ 4) Remover duplicadas
  const fotosUnicas = photos.filter(
    (f, i, arr) => arr.findIndex(o => o.image_data === f.image_data) === i
  );

  console.log(`🔥 TOTAL FINAL DE FOTOS: ${fotosUnicas.length}`);

  return fotosUnicas;
}

return await extrairFotos();

