partes.shift(); // remove lixo antes do primeiro EMAIL

const resultados = [];

partes.forEach(parte => {
  let email = null;
  let senha = null;

  // ---------------------------------------------
  // EMAIL VISÍVEL
  // ---------------------------------------------
  const emailMatch = parte.match(/<span[^>]*>([^<@]+@[^<]+)<\/span>/i);
  if (emailMatch && emailMatch[1]) {
    email = emailMatch[1].trim().toLowerCase();
  }

  // ---------------------------------------------
  // EMAIL OFUSCADO (Cloudflare)
  // ---------------------------------------------
  if (!email) {
    const cfMatch = parte.match(/data-cfemail=["']([a-f0-9]+)["']/i);
    if (cfMatch && cfMatch[1]) {
      const cfemail = cfMatch[1];
      let decoded = '';
      const key = parseInt(cfemail.substr(0, 2), 16);
      for (let i = 2; i < cfemail.length; i += 2) {
        decoded += String.fromCharCode(
          parseInt(cfemail.substr(i, 2), 16) ^ key
        );
      }
      if (decoded.includes('@')) {
        email = decoded.toLowerCase();
      }
    }
  }

  // ---------------------------------------------
  // SENHA
  // ---------------------------------------------
  const senhaMatch = parte.match(
    /<strong>SENHA:\s*<\/strong>\s*<span[^>]*>([^<]+)<\/span>/i
  );
  if (senhaMatch && senhaMatch[1]) {
    senha = senhaMatch[1].trim();
  }

  // ---------------------------------------------
  // SE TEM EMAIL + SENHA → SALVA
  // ---------------------------------------------
  if (email && senha) {
    resultados.push({
      json: {
        cpf_id,
        email,
        senha
      }
    });
  }
});

return resultados;

